  1→import { useState } from 'react';
  2→import { Navigate } from 'react-router-dom';
  3→import { useAuth } from '../hooks/useAuth';
  4→import { hasProfileSectorTargets } from '../utils/sector-targeting';
  5→
  6→type Mode = 'login' | 'signup';
  7→
  8→/**
  9→ * Ecran connexion / inscription de LeadRadar.
 10→ */
 11→const AuthPage = (): JSX.Element => {
 12→  const { user, profile, login, signup, resetPassword, loading, error, clearError } = useAuth();
 13→  const [mode, setMode] = useState<Mode>('login');
 14→  const [fullName, setFullName] = useState<string>('');
 15→  const [email, setEmail] = useState<string>('');
 16→  const [password, setPassword] = useState<string>('');
 17→  const [inlineError, setInlineError] = useState<string | null>(null);
 18→  const [info, setInfo] = useState<string | null>(null);
 19→
 20→  const hasSectors = hasProfileSectorTargets(profile);
 21→
 22→  if (user && hasSectors) {
 23→    return <Navigate replace to="/radar" />;
 24→  }
 25→  if (user && !hasSectors) {
 26→    return <Navigate replace to="/onboarding/sector" />;
 27→  }
 28→
 29→  const isEmailValid = /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email);
 30→
 31→  /**
 32→   * Reinitialise les messages d'etat.
 33→   */
 34→  const resetMessages = (): void => {
 35→    setInlineError(null);
 36→    setInfo(null);
 37→    clearError();
 38→  };
 39→
 40→  /**
 41→   * Soumet la connexion.
 42→   */
 43→  const submitLogin = async (): Promise<void> => {
 44→    resetMessages();
 45→    if (!isEmailValid) {
 46→      setInlineError('Adresse email invalide.');
 47→      return;
 48→    }
 49→    if (password.length < 6) {
 50→      setInlineError('Le mot de passe doit contenir au moins 6 caracteres.');
 51→      return;
 52→    }
 53→    await login(email.trim().toLowerCase(), password);
 54→  };
 55→
 56→  /**
 57→   * Soumet l'inscription.
 58→   */
 59→  const submitSignup = async (): Promise<void> => {
 60→    resetMessages();
 61→    if (fullName.trim().length < 2) {
 62→      setInlineError('Le nom complet est requis.');
 63→      return;
 64→    }
 65→    if (!isEmailValid) {
 66→      setInlineError('Adresse email invalide.');
 67→      return;
 68→    }
 69→    if (password.length < 8) {
 70→      setInlineError('Le mot de passe doit contenir au moins 8 caracteres.');
 71→      return;
 72→    }
 73→    const ok = await signup(email.trim().toLowerCase(), password, fullName.trim());
 74→    if (ok) {
 75→      setInfo('Compte cree. Verifiez votre email si la confirmation est active.');
 76→    }
 77→  };
 78→
 79→  /**
 80→   * Demarre le reset mot de passe.
 81→   */
 82→  const onResetPassword = async (): Promise<void> => {
 83→    resetMessages();
 84→    if (!isEmailValid) {
 85→      setInlineError('Entrez un email valide pour recevoir le lien de reinitialisation.');
 86→      return;
 87→    }
 88→    const ok = await resetPassword(email.trim().toLowerCase());
 89→    if (ok) {
 90→      setInfo('Email de reinitialisation envoye.');
 91→    }
 92→  };
 93→
 94→  return (
 95→    <div className="dot-grid-bg flex min-h-screen items-center justify-center bg-[#0B0F1A] px-4 py-10 text-white">
 96→      <div className="w-full max-w-md rounded-2xl border border-[#1E293B] bg-[#111827] p-6 shadow-2xl shadow-black/40 sm:p-8">
 97→        <div className="mb-6 text-center">
 98→          <div className="mb-2 inline-flex items-center gap-2">
 99→            <span className="text-2xl text-[#10B981]">📡</span>
100→            <h1 className="font-outfit text-2xl font-bold tracking-tight">LeadRadar</h1>
101→          </div>
102→          <p className="text-sm italic text-slate-300">Vos prochains clients. Detectes. Analyses. Livres.</p>
103→        </div>
104→
105→        <div className="mb-6 grid grid-cols-2 rounded-lg border border-[#1E293B] bg-[#0F172A] p-1 text-sm">
106→          <button
107→            type="button"
108→            onClick={() => {
109→              setMode('login');
110→              resetMessages();
111→            }}
112→            className={`rounded-md px-3 py-2 font-semibold transition ${
113→              mode === 'login' ? 'bg-[#10B981] text-[#052E16]' : 'text-slate-300 hover:text-white'
114→            }`}
115→          >
116→            Connexion
117→          </button>
118→          <button
119→            type="button"
120→            onClick={() => {
121→              setMode('signup');
122→              resetMessages();
123→            }}
124→            className={`rounded-md px-3 py-2 font-semibold transition ${
125→              mode === 'signup' ? 'bg-[#10B981] text-[#052E16]' : 'text-slate-300 hover:text-white'
126→            }`}
127→          >
128→            Inscription
129→          </button>
130→        </div>
131→
132→        {mode === 'login' ? (
133→          <form
134→            className="space-y-4"
135→            onSubmit={(event) => {
136→              event.preventDefault();
137→              void submitLogin();
138→            }}
139→          >
140→            <label className="block text-sm text-slate-200">
141→              Email
142→              <input
143→                type="email"
144→                value={email}
145→                onChange={(event) => setEmail(event.target.value)}
146→                className="mt-1 w-full rounded-lg border border-[#1E293B] bg-[#0B1220] px-3 py-2 outline-none transition focus:border-[#10B981]"
147→                placeholder="vous@entreprise.com"
148→                autoComplete="email"
149→                required
150→              />
151→            </label>
152→            <label className="block text-sm text-slate-200">
153→              Mot de passe
154→              <input
155→                type="password"
156→                value={password}
157→                onChange={(event) => setPassword(event.target.value)}
158→                className="mt-1 w-full rounded-lg border border-[#1E293B] bg-[#0B1220] px-3 py-2 outline-none transition focus:border-[#10B981]"
159→                placeholder="********"
160→                autoComplete="current-password"
161→                required
162→              />
163→            </label>
164→            <button
165→              type="submit"
166→              disabled={loading}
167→              className="w-full rounded-lg bg-[#10B981] px-4 py-2.5 font-semibold text-[#052E16] transition hover:bg-emerald-400 disabled:cursor-not-allowed disabled:opacity-60"
168→            >
169→              {loading ? 'Connexion...' : 'Se connecter'}
170→            </button>
171→            <button
172→              type="button"
173→              onClick={() => {
174→                void onResetPassword();
175→              }}
176→              className="w-full text-sm text-slate-300 underline-offset-4 transition hover:text-white hover:underline"
177→            >
178→              Mot de passe oublie
179→            </button>
180→          </form>
181→        ) : (
182→          <form
183→            className="space-y-4"
184→            onSubmit={(event) => {
185→              event.preventDefault();
186→              void submitSignup();
187→            }}
188→          >
189→            <label className="block text-sm text-slate-200">
190→              Nom complet
191→              <input
192→                type="text"
193→                value={fullName}
194→                onChange={(event) => setFullName(event.target.value)}
195→                className="mt-1 w-full rounded-lg border border-[#1E293B] bg-[#0B1220] px-3 py-2 outline-none transition focus:border-[#10B981]"
196→                placeholder="Marie Dupont"
197→                autoComplete="name"
198→                required
199→              />
200→            </label>
201→            <label className="block text-sm text-slate-200">
202→              Email
203→              <input
204→                type="email"
205→                value={email}
206→                onChange={(event) => setEmail(event.target.value)}
207→                className="mt-1 w-full rounded-lg border border-[#1E293B] bg-[#0B1220] px-3 py-2 outline-none transition focus:border-[#10B981]"
208→                placeholder="vous@entreprise.com"
209→                autoComplete="email"
210→                required
211→              />
212→            </label>
213→            <label className="block text-sm text-slate-200">
214→              Mot de passe
215→              <input
216→                type="password"
217→                value={password}
218→                onChange={(event) => setPassword(event.target.value)}
219→                className="mt-1 w-full rounded-lg border border-[#1E293B] bg-[#0B1220] px-3 py-2 outline-none transition focus:border-[#10B981]"
220→                placeholder="8 caracteres minimum"
221→                autoComplete="new-password"
222→                required
223→              />
224→            </label>
225→            <button
226→              type="submit"
227→              disabled={loading}
228→              className="w-full rounded-lg bg-[#10B981] px-4 py-2.5 font-semibold text-[#052E16] transition hover:bg-emerald-400 disabled:cursor-not-allowed disabled:opacity-60"
229→            >
230→              {loading ? 'Creation...' : 'Creer mon compte'}
231→            </button>
232→          </form>
233→        )}
234→
235→        {inlineError ? <p className="mt-4 text-sm text-red-400">{inlineError}</p> : null}
236→        {error ? <p className="mt-4 text-sm text-red-400">{error}</p> : null}
237→        {info ? <p className="mt-4 text-sm text-emerald-400">{info}</p> : null}
238→      </div>
239→    </div>
240→  );
241→};
242→
243→export default AuthPage;
