 12→const seededScore = (seed: number, offset: number, min = 15, max = 85): number => {
 13→  const raw = ((seed * 37 + offset * 19 + 11) * 17) % 1000;
 14→  return min + Math.round((raw / 1000) * (max - min));
 15→};
