 17→const fallbackSimulation = async (url: string, brandName?: string): Promise<EeatAuditResult> => {
 18→  await new Promise(resolve => setTimeout(resolve, 2800));
 19→
 20→  let hostname: string;
 21→  try { hostname = new URL(url).hostname; } catch { hostname = url; }
 22→  const brand = brandName || hostname;
 23→  const seed = url.length + hostname.length;
 24→
 25→  const experience = seededScore(seed, 1);
 26→  const expertise = seededScore(seed, 2);
 27→  const authoritativeness = seededScore(seed, 3);
 28→  const trustworthiness = seededScore(seed, 4);
 29→  const overall = Math.round((experience + expertise + authoritativeness + trustworthiness) / 4);
 30→
 31→  const findings: EeatAuditResult['findings'] = [
 32→    { category: 'experience', status: experience >= 50 ? 'present' : 'missing', element: 'Temoignages de premiere main', impact: 'high', recommendation: 'Ajouter des etudes de cas detaillees avec des resultats concrets et mesurables.' },
 33→    { category: 'experience', status: experience >= 60 ? 'present' : 'incomplete', element: 'Contenu original (photos, videos)', impact: 'medium', recommendation: 'Integrer des visuels originaux (captures, photos terrain, videos) pour prouver l\'experience.' },
 34→    { category: 'experience', status: experience >= 40 ? 'incomplete' : 'missing', element: 'Details specifiques au metier', impact: 'medium', recommendation: 'Enrichir le contenu avec des termes techniques et des details concrets du secteur.' },
 35→    { category: 'expertise', status: expertise >= 50 ? 'present' : 'missing', element: 'Auteur identifie avec bio', impact: 'high', recommendation: 'Ajouter un bloc auteur avec bio, photo et credentials sur chaque article.' },
